using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build AI client with automatic function invocation ───────────────────────
var researchTools = new ResearchTools();

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(researchTools.SearchWeb),
        AIFunctionFactory.Create(researchTools.SaveNote),
        AIFunctionFactory.Create(researchTools.GetNotes),
    ]
};

// ── Conversation history ─────────────────────────────────────────────────────
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a given topic
        by searching the web, recording key findings as notes, and then producing
        a well-organized summary.

        Follow this workflow:
        1. Break the topic into several focused sub-queries.
        2. Use the SearchWeb tool for each sub-query.
        3. Save the most important findings with the SaveNote tool.
        4. Once you have enough information, call GetNotes to review everything,
           then write a comprehensive summary with key facts and sources.
        """)
};

// ── Interactive REPL ─────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════════════╗");
Console.WriteLine("║           🔍  Research Agent  🔍                ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.  ║");
Console.WriteLine("╚══════════════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input)) continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    messages.Add(new(ChatRole.User,
        $"Please research the following topic and provide a detailed summary: {input}"));

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n⏳ Researching… (the agent may call tools several times)\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(messages, chatOptions);

        foreach (var msg in response.Messages)
            messages.Add(msg);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("── Research Summary ────────────────────────────");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");
return;

// ═════════════════════════════════════════════════════════════════════════════
//  Tool implementations
// ═════════════════════════════════════════════════════════════════════════════

sealed class ResearchTools
{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _http = new();

    public ResearchTools()
    {
        _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
        _http.Timeout = TimeSpan.FromSeconds(15);
    }

    [Description("Search the web for information about a topic. Returns relevant results and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        Console.ResetColor();

        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                + "&format=json&no_html=1&t=ResearchAgent";
        try
        {
            var json = await _http.GetStringAsync(url);
            var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var parts = new List<string>();

            var heading = root.GetProperty("Heading").GetString();
            if (!string.IsNullOrWhiteSpace(heading))
                parts.Add($"# {heading}");

            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                parts.Add(abstractText);

            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractSource))
                parts.Add($"(Source: {abstractSource})");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text))
                    {
                        var t = text.GetString();
                        if (!string.IsNullOrWhiteSpace(t))
                            parts.Add($"• {t}");
                    }
                }
            }

            return parts.Count > 0
                ? string.Join("\n", parts)
                : "No results found. Try different keywords.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note to record an important finding.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        _notes.Add((title, content));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes to review before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📖 Reviewing {_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"── Note {i + 1}: {n.Title} ──\n{n.Content}"));
    }
}

